//! MQL5 Expert Advisor recognizer for the Gnosis polyglot scanner.
//!
//! Detects MetaTrader 5 Expert Advisors (.mq5) and extracts their
//! trading topology as a FrameworkTopology. MQL5 EAs are not HTTP servers,
//! but they ARE event-driven topologies:
//!
//!   OnInit   → initialization (like constructor / setup)
//!   OnTick   → the main event loop (like request handler)
//!   OnDeinit → cleanup
//!
//! The recognizer maps these to route-like primitives:
//!   OnInit   → "INIT" handler
//!   OnTick   → "TICK" handler
//!   OnDeinit → "DEINIT" handler
//!   input params → config entries
//!   indicator handles → middleware
//!
//! This enables `gnosis analyze` to consume .mq5 files and extract
//! trading strategy topologies for translation to .gg format.

use std::collections::HashMap;

use crate::cfg::ControlFlowGraph;
use crate::framework_recognizer::{
    FrameworkRecognizer, FrameworkTopology, HttpMethod, Middleware, Route,
};

/// MQL5 Expert Advisor recognizer.
pub struct Mql5Recognizer;

impl FrameworkRecognizer for Mql5Recognizer {
    fn framework_id(&self) -> &str {
        "mql5"
    }

    fn language(&self) -> &str {
        "mql5"
    }

    fn detect(
        &self,
        source: &str,
        file_path: &str,
        cfgs: &[ControlFlowGraph],
    ) -> Option<FrameworkTopology> {
        // Quick check: is this an MQL5 file?
        if !file_path.ends_with(".mq5") && !file_path.ends_with(".mqh") {
            return None;
        }

        // Must have at least OnTick or OnInit
        let has_on_tick = source.contains("OnTick");
        let has_on_init = source.contains("OnInit");
        if !has_on_tick && !has_on_init {
            return None;
        }

        let mut routes = Vec::new();
        let mut middleware = Vec::new();
        let mut config = HashMap::new();

        // Extract event handlers as "routes"
        if has_on_init {
            if let Some((start, end)) = find_function_bounds(source, "OnInit") {
                routes.push(Route {
                    method: HttpMethod::All, // Not HTTP, but maps to "lifecycle event"
                    path: "/lifecycle/init".to_string(),
                    handler_name: "OnInit".to_string(),
                    handler_cfg_index: find_cfg_index(cfgs, "OnInit"),
                    source_start: start,
                    source_end: end,
                });
            }
        }

        if has_on_tick {
            if let Some((start, end)) = find_function_bounds(source, "OnTick") {
                routes.push(Route {
                    method: HttpMethod::Post, // Tick = incoming data event
                    path: "/tick".to_string(),
                    handler_name: "OnTick".to_string(),
                    handler_cfg_index: find_cfg_index(cfgs, "OnTick"),
                    source_start: start,
                    source_end: end,
                });
            }
        }

        if source.contains("OnDeinit") {
            if let Some((start, end)) = find_function_bounds(source, "OnDeinit") {
                routes.push(Route {
                    method: HttpMethod::All,
                    path: "/lifecycle/deinit".to_string(),
                    handler_name: "OnDeinit".to_string(),
                    handler_cfg_index: find_cfg_index(cfgs, "OnDeinit"),
                    source_start: start,
                    source_end: end,
                });
            }
        }

        // Extract functions as additional routes
        for func_name in &[
            "TrainLinearModel",
            "PredictPriceChange",
            "CalculateLotSize",
            "GetMLSLTP",
            "TrailSLTP",
            "CheckLatency",
        ] {
            if source.contains(func_name) {
                if let Some((start, end)) = find_function_bounds(source, func_name) {
                    routes.push(Route {
                        method: HttpMethod::Post,
                        path: format!("/strategy/{}", to_kebab(func_name)),
                        handler_name: func_name.to_string(),
                        handler_cfg_index: find_cfg_index(cfgs, func_name),
                        source_start: start,
                        source_end: end,
                    });
                }
            }
        }

        // Extract input parameters as config
        let mut order = 0;
        for line in source.lines() {
            let trimmed = line.trim();
            if trimmed.starts_with("input ") || trimmed.starts_with("sinput ") {
                if let Some(param) = parse_input_param(trimmed) {
                    config.insert(param.0.clone(), param.1.clone());
                    middleware.push(Middleware {
                        name: format!("input:{}", param.0),
                        path_prefix: None,
                        handler_cfg_index: None,
                        order,
                    });
                    order += 1;
                }
            }
        }

        // Extract indicator handles as middleware
        for indicator in &["iRSI", "iBands", "iMA", "iATR", "iCustom"] {
            if source.contains(indicator) {
                middleware.push(Middleware {
                    name: format!("indicator:{}", indicator),
                    path_prefix: Some("/tick".to_string()),
                    handler_cfg_index: None,
                    order,
                });
                order += 1;
            }
        }

        // Extract CTrade usage
        if source.contains("CTrade") {
            middleware.push(Middleware {
                name: "CTrade".to_string(),
                path_prefix: Some("/tick".to_string()),
                handler_cfg_index: None,
                order,
            });
            config.insert("trade_library".to_string(), "CTrade".to_string());
        }

        Some(FrameworkTopology {
            framework: "mql5".to_string(),
            language: "mql5".to_string(),
            file_path: file_path.to_string(),
            routes,
            middleware,
            listen_port: None, // Not a network server
            config,
        })
    }
}

// ============================================================================
// Helpers
// ============================================================================

/// Find approximate byte bounds of a function definition.
fn find_function_bounds(source: &str, name: &str) -> Option<(usize, usize)> {
    // Simple heuristic: find "name(" and then track brace nesting
    let pattern = format!("{}(", name);
    let start_idx = source.find(&pattern)?;

    // Find opening brace
    let after_sig = &source[start_idx..];
    let brace_offset = after_sig.find('{')?;
    let brace_start = start_idx + brace_offset;

    // Track nesting to find matching close
    let mut depth = 0;
    let mut end_idx = brace_start;
    for (i, ch) in source[brace_start..].char_indices() {
        match ch {
            '{' => depth += 1,
            '}' => {
                depth -= 1;
                if depth == 0 {
                    end_idx = brace_start + i + 1;
                    break;
                }
            }
            _ => {}
        }
    }

    Some((start_idx, end_idx))
}

/// Find the CFG index for a function name.
fn find_cfg_index(cfgs: &[ControlFlowGraph], name: &str) -> Option<usize> {
    cfgs.iter().position(|cfg| cfg.function_name == name)
}

/// Parse an MQL5 input parameter line.
/// e.g., "input double RiskPercent = 10.0; // Risk per trade"
fn parse_input_param(line: &str) -> Option<(String, String)> {
    let stripped = line
        .trim_start_matches("input ")
        .trim_start_matches("sinput ");

    // Split on '=' to get name and default value
    let parts: Vec<&str> = stripped.splitn(2, '=').collect();
    if parts.len() < 2 {
        return None;
    }

    // Extract the variable name (last word before '=')
    let name_part = parts[0].trim();
    let name = name_part.split_whitespace().last()?.to_string();

    // Extract the default value (before any comment)
    let value = parts[1]
        .split("//")
        .next()?
        .trim()
        .trim_end_matches(';')
        .trim()
        .to_string();

    Some((name, value))
}

/// Convert CamelCase to kebab-case.
fn to_kebab(s: &str) -> String {
    let mut result = String::new();
    for (i, ch) in s.chars().enumerate() {
        if ch.is_uppercase() && i > 0 {
            result.push('-');
        }
        result.push(ch.to_ascii_lowercase());
    }
    result
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_detect_mql5_ea() {
        let source = r#"
input double RiskPercent = 10.0; // Risk percentage
input int SlPoints = 2000;

#include <Trade\Trade.mqh>
CTrade trade;
int rsiHandle;

int OnInit() {
    rsiHandle = iRSI(_Symbol, PERIOD_M1, 14, PRICE_CLOSE);
    return INIT_SUCCEEDED;
}

void OnTick() {
    double prediction = PredictPriceChange();
    if (prediction > 0) {
        trade.Buy(0.01, _Symbol);
    }
}

double PredictPriceChange() {
    return 0.0;
}
"#;

        let recognizer = Mql5Recognizer;
        let result = recognizer.detect(source, "test.mq5", &[]);
        assert!(result.is_some());

        let topology = result.unwrap();
        assert_eq!(topology.framework, "mql5");
        assert_eq!(topology.language, "mql5");

        // Should find OnInit, OnTick, PredictPriceChange
        assert!(topology.routes.len() >= 3);

        // Should extract input params
        assert_eq!(
            topology.config.get("RiskPercent"),
            Some(&"10.0".to_string())
        );
        assert_eq!(topology.config.get("SlPoints"), Some(&"2000".to_string()));

        // Should detect indicator and trade library middleware
        let middleware_names: Vec<&str> = topology
            .middleware
            .iter()
            .map(|m| m.name.as_str())
            .collect();
        assert!(middleware_names.iter().any(|n| n.contains("iRSI")));
        assert!(middleware_names.iter().any(|n| *n == "CTrade"));
    }

    #[test]
    fn test_rejects_non_mql5() {
        let recognizer = Mql5Recognizer;
        let result = recognizer.detect("const app = express();", "test.js", &[]);
        assert!(result.is_none());
    }

    #[test]
    fn test_parse_input_param() {
        let result = parse_input_param("input double RiskPercent = 10.0; // Risk percentage");
        assert_eq!(
            result,
            Some(("RiskPercent".to_string(), "10.0".to_string()))
        );

        let result2 = parse_input_param("input int SlPoints = 2000;");
        assert_eq!(result2, Some(("SlPoints".to_string(), "2000".to_string())));
    }

    #[test]
    fn test_to_kebab() {
        assert_eq!(to_kebab("TrainLinearModel"), "train-linear-model");
        assert_eq!(to_kebab("PredictPriceChange"), "predict-price-change");
    }
}
